     * Finds all "valid" elements in the array nums.
     * An element nums[i] is valid if:
     * 1. It is strictly greater than all elements to its left.
     * 2. It is strictly greater than all elements to its right.
     * The first and last elements are always valid.
     *
     * @param nums The input integer array.
     * @return An array containing all valid elements in order.
     */
    public static long[] solve(long[] nums) {
        int n = nums.length;
        if (n == 0) {
            return new long[0];
        }
        if (n == 1) {
            return new long[]{nums[0]};
        }

        // Step 1: Precompute maximums for the left and right sides.

        // leftMax[i] stores the maximum of nums[0...i-1]
        // We can use this to check if nums[i] > max(nums[0...i-1])
        long[] leftMax = new long[n];
        leftMax[0] = Long.MIN_VALUE; // No element to the left of the first element
        for (int i = 1; i < n; i++) {
            leftMax[i] = Math.max(leftMax[i - 1], nums[i - 1]);
